(()=>{var e=document.querySelector(".menu-mobile"),t=document.querySelector(".page-header__menu");t.addEventListener("click",()=>{e.classList.contains("menu-mobile--close")&&(e.classList.remove("menu-mobile--close"),e.classList.add("menu-mobile--active"))});var o=document.querySelector(".modal"),c=o.querySelector(".modal__overlay"),s=document.querySelector(".product__order");s.addEventListener("click",()=>{o.classList.add("modal--show")});c.addEventListener("click",()=>{o.classList.remove("modal--show")});})();
